// User types
export interface User {
  id: string;
  email: string;
  name: string;
  mobile: string;
  role: 'User' | 'Admin' | 'Technician';
  profile_pic?: string;
}

// API Response Data types
export interface UserProfileData {
  id?: string;
  email_id?: string;
  customer_name?: string;
  employee_name?: string;
  mobile_number?: string;
  phone_number?: string;
  profile_pic?: string;
  address1?: string;
  address2?: string;
  gender?: string;
  country?: string;
}

export interface LoginResponseData {
  id?: string;
  email_id?: string;
  customer_name?: string;
  employee_name?: string;
  mobile_number?: string;
  phone_number?: string;
  profile_pic?: string;
}

// Service types
export interface Service {
  service_id: string;
  service_name: string;
  description: string;
  image_path?: string; // Added for service images
  category?: string;
}

export interface ServiceTypeData {
  typeName: string;
  pricingFields: PricingField[];
  id?: number;
}

export interface PricingField {
  roomSize: string;
  price: string;
  id?: number;
}

// Booking types
export interface Booking {
  booking_id: string;
  service_name: string;
  service_date: string;
  time_slot?: string;
  service_time?: string;
  service_address?: string;
  special_notes?: string;
  subtotal?: number;
  discount_amount?: number;
  total_amount: number;
  payment_method: string;
  payment_status?: string;
  status?: 'pending' | 'confirmed' | 'accepted' | 'completed' | 'cancelled';
  booking_status?: string; // Added for admin API compatibility
  technician_status?: 'assigned' | 'reached' | 'started' | 'completed';
  created_at: string;
  customer_name?: string;
  customer_email?: string;
  customer_phone?: string;
  assigned_technician_name?: string;
  technician_phone?: string;
}

export interface BookingResponse {
  status: string;
  message?: string;
  booking_id?: string;
}

// Offer types
export interface Offer {
  offer_id: string;
  offer_name: string;
  description: string;
  discount_percentage: number;
  valid_until: string;
  image_url?: string;
  is_active: boolean;
  offer_banner_location?: string; // Added for offer banner images
  coupon_number?: string;
  offer_percentage?: string;
  status?: string;
}

// Employee types
export interface Employee {
  id: string;
  name: string;
  mobile: string;
  address: string;
  email: string;
  serviceType: string;
  idProof?: string;
}

// Contact types
export interface ContactQuery {
  query_id: string;
  first_name: string;
  last_name: string;
  email: string;
  phone: string;
  subject: string;
  message: string;
  status: 'pending' | 'resolved';
  created_at: string;
}

// API Response types
export interface ApiResponse<T> {
  status: 'success' | 'error';
  message?: string;
  data?: T;
  sessionid?: string;
  session_expiry?: string;
}

// Form types
export interface LoginForm {
  email: string;
  password: string;
  role: 'User' | 'Admin' | 'Technician';
}

export interface SignupForm {
  customer_name: string;
  mobile_number: string;
  password: string;
}

export interface ContactForm {
  first_name: string;
  last_name: string;
  email: string;
  phone: string;
  subject: string;
  message: string;
}

// Navigation types
export interface NavItem {
  label: string;
  path: string;
  icon: string;
  requiresAuth?: boolean;
  roles?: string[];
}

// Razorpay types
declare global {
  interface Window {
    Razorpay: any;
  }
}

export interface RazorpayOptions {
  key: string;
  amount: number;
  name: string;
  description: string;
  prefill: {
    contact?: string;
    email?: string;
  };
  external?: {
    wallets: string[];
  };
  handler: (response: RazorpayResponse) => void;
  modal?: {
    ondismiss?: () => void;
  };
}

export interface RazorpayResponse {
  razorpay_payment_id: string;
  razorpay_order_id: string;
  razorpay_signature: string;
}
